import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

const Login = () => {
  const [formData, setFormData] = useState({
    LoginName: '',
    Password: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const response = await axios.post('https://soni.loyalstring.co.in/api/ProductMaster/AuthLogin', formData);
      console.log('Login response:', response.data);
      
      if (!response.data) {
        throw new Error('No response data received from server');
      }

      // Get token from response
      const token = response.data.Token;
      if (!token) {
        throw new Error('No token received from server');
      }

      // Extract client code from JWT token
      let userInfo;
      try {
        const tokenData = JSON.parse(atob(token.split('.')[1]));
        userInfo = {
          Username: formData.LoginName,
          ClientCode: tokenData.ClientCode
        };
        console.log('Extracted userInfo from token:', userInfo);
        if (!userInfo.ClientCode) {
          throw new Error('Client code not found in token');
        }
      } catch (tokenError) {
        console.error('Token parsing error:', tokenError);
        throw new Error('Failed to extract client code from token');
      }

      localStorage.setItem('token', token);
      localStorage.setItem('userInfo', JSON.stringify(userInfo));
      
      // Show success message with client code
      toast.success(`Welcome ${userInfo.Username}! Client Code: ${userInfo.ClientCode}`, {
        position: "top-right",
        autoClose: 2000,
        hideProgressBar: false,
        closeOnClick: true,
        pauseOnHover: true,
        draggable: true,
        theme: "colored"
      });

      // Redirect to dashboard immediately after login
      navigate('/dashboard');

    } catch (err) {
      console.error('Login error:', err);
      const errorMessage = err.response?.data?.Message || err.message || 'Login failed. Please try again.';
      setError(errorMessage);
      toast.error(errorMessage, {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #ffffff 0%, #e0e0e0 100%)',
      fontFamily: 'Poppins, Montserrat, Arial, sans-serif',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center'
    }}>
      <ToastContainer />
      <div className="row justify-content-center w-100">
        <div className="col-md-6">
          <div className="card shadow-lg border-0" style={{ borderRadius: 18 }}>
            <div className="card-body p-5">
              <div className="text-center mb-4">
                <i className="fas fa-rss fa-3x text-primary mb-2"></i>
                <h2 className="card-title mb-1 fw-bold" style={{ fontFamily: 'Poppins, Montserrat, Arial, sans-serif', letterSpacing: 1 }}>RFID API Login</h2>
                <div className="mb-2 text-primary fw-semibold" style={{ fontSize: '1.1rem', letterSpacing: 1 }}>Loyalstring Pvt Ltd</div>
                <div className="text-muted mb-2" style={{ fontSize: '0.95rem' }}>Enter your credentials to access the RFID API Dashboard</div>
              </div>
              {error && (
                <div className="alert alert-danger poppins" style={{ fontWeight: 500 }}>
                  <i className="fas fa-exclamation-circle me-2"></i>
                  {error}
                </div>
              )}
              <form onSubmit={handleSubmit} autoComplete="off">
                <div className="mb-3">
                  <label htmlFor="LoginName" className="form-label fw-semibold">
                    <i className="fas fa-user me-2 text-primary"></i>
                    Login Name
                  </label>
                  <input
                    type="text"
                    className="form-control shadow-sm"
                    id="LoginName"
                    name="LoginName"
                    value={formData.LoginName}
                    onChange={handleChange}
                    required
                    placeholder="Enter your login name"
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="Password" className="form-label fw-semibold">
                    <i className="fas fa-lock me-2 text-danger"></i>
                    Password
                  </label>
                  <input
                    type="password"
                    className="form-control shadow-sm"
                    id="Password"
                    name="Password"
                    value={formData.Password}
                    onChange={handleChange}
                    required
                    placeholder="Enter your password"
                  />
                </div>
                <button
                  type="submit"
                  className="btn w-100 fw-bold shadow-sm poppins"
                  style={{
                    fontSize: '1.1rem',
                    letterSpacing: 1,
                    background: 'linear-gradient(90deg, #1e3c72 0%, #2a5298 100%)',
                    color: '#fff',
                    border: 'none',
                    transition: '0.2s',
                    boxShadow: '0 2px 8px rgba(30,60,114,0.15)'
                  }}
                  disabled={loading}
                  onMouseOver={e => e.currentTarget.style.background = 'linear-gradient(90deg, #2a5298 0%, #1e3c72 100%)'}
                  onMouseOut={e => e.currentTarget.style.background = 'linear-gradient(90deg, #1e3c72 0%, #2a5298 100%)'}
                >
                  {loading ? (
                    <>
                      <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                      Logging in...
                    </>
                  ) : (
                    <>
                      <i className="fas fa-sign-in-alt me-2"></i>
                      Login
                    </>
                  )}
                </button>
              </form>
              <div className="text-center mt-3">
                <p className="mb-0">
                  Don't have an account?{' '}
                  <a href="/register" className="fw-bold text-primary text-decoration-none" style={{ transition: 'color 0.2s' }}>
                    <i className="fas fa-user-plus me-1"></i>
                    Register
                  </a>
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Login;
